import{_ as a,o as t,c as b,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"圣约十字","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/2.C级/圣约十字 .md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/2.C级/圣约十字 .md"}'),o={name:"4.资源分区/7.物品与装备/2.武器/远程武器/2.C级/圣约十字 .md"};function d(p,e,_,l,i,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"圣约十字",tabindex:"-1"},[n("圣约十字 "),r("a",{class:"header-anchor",href:"#圣约十字","aria-label":'Permalink to "圣约十字"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌033")])])],-1),s('<h1 id="圣约十字-1" tabindex="-1">圣约十字 <a class="header-anchor" href="#圣约十字-1" aria-label="Permalink to &quot;圣约十字&quot;">​</a></h1><p>圣约十字<br> C+1000<br> 武器：盾/霰弹枪<br> 科技本质<br> ‘我主赐予我神圣之启示’<br> ‘教皇赠予我制恶之十字’<br> ‘我当制裁一切不恕罪恶’<br> ‘我当传播恶主神之福光’<br> 由新兴教国独立研发的神圣式制恶圣约十字<br> 这个银红色的巨大十字长处约有六英尺高，宽处约有三点五英尺宽，整体进行了防御特化，能够有效阻断物理意义上的部分影响。<br> 十字其中一侧装有把手与弹药填充口，能够如同手持盾牌一般手持，并在内部装载了泵动式霰弹发射器，必要时能够在十字架底部发射出赤红的龙息火焰弹，可以轻易对碳基生物造成毁灭性打击。</p><p>盾牌模式 此时视为11L武器伤害的重盾<br> 拥有双手 格挡5特性<br> 造成钝击伤害 体积4</p><p>霰弹模式 此时视为12L武器伤害的霰弹枪<br> 拥有高速5 攻击距离不超过15米内的单位时获得2威猛 长点射 特性<br> 造成穿刺伤害 体积4 载弹11+1 射程40米</p><p>值得注意的是，使用霰弹模式时请自行备足弹药<br> 【爆发火力】<br> 以本武器进行攻击时，可以使用一个自由动作将弹药转化为龙息弹，使得攻击时转为对目标造成火焰伤害。<br> 【神圣庇护】<br> 巨大的十字无论如何都可以将你笼罩其中，手持武器时，你获得1点遮蔽防御。<br> 【盾与枪】<br> 消耗一个迅捷动作，立刻对武器进行一次【火弹装填】或对武器进行一次【猛击祝福】祷告，并使得武器在霰弹攻击模式与盾牌模式之间进行一次切换。<br> ——火弹装填<br> 你当知晓，火焰为主的目光<br> 此刻，祂注视你，你当感恩<br> 它将如祂令耶稣基督赦免罪人一般，赦免你的罪<br> 若进行【火弹装填】，武器此时将被切换为霰弹枪模式，无法视为盾进行相关的动作或技艺的使用，直到进行切换为止，随后，在下一次攻击中，你的攻击将对前方造成7.5米的扇形范围伤害，切换后失效。<br> ——猛击祝福<br> 你当知晓，主可令地动山摇<br> 此刻，我持耶稣基督之象征，罪人当止步于此<br> 亦或者，将遭受日光（存疑）灼烧（确信）之刑。<br> 若进行【猛击祝福】，武器此时将被切换为盾牌模式，无法作为霰弹枪进行相关的动作或技艺的使用，直到切换为止，随后，你若在下一次攻击中使用圣约十字的头部进行撞击攻击那么这时你可以一个自由动作令圣约十字朝反方向进行一次助推射击，反作用力会使得你的这次近战攻击视为附带了一次冲撞效果。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const m=a(o,[["render",d]]);export{f as __pageData,m as default};
